function getLegalLanguage() {
  if (typeof window.getCurrentLanguage === "function") {
    return window.getCurrentLanguage();
  }
  return "nl";
}

function renderLegalPage() {
  const pageId = document.body?.dataset?.legalPage;
  if (!pageId || !LEGAL_PAGE_CONTENT[pageId]) return;

  const lang = getLegalLanguage();
  const content = LEGAL_PAGE_CONTENT[pageId][lang] || LEGAL_PAGE_CONTENT[pageId].nl;
  const heroMain = document.getElementById("legal-hero-main");
  const sideCard = document.getElementById("legal-hero-sidecard");
  const summary = document.getElementById("legal-summary");
  const sections = document.getElementById("legal-content");
  const footerNote = document.getElementById("legal-footer-note");
  const metaDescription = document.querySelector('meta[name="description"]');

  document.title = content.pageTitle;
  if (metaDescription) metaDescription.setAttribute("content", content.metaDescription);

  if (heroMain) {
    heroMain.innerHTML = `
      <p class="eyebrow">${content.eyebrow}</p>
      <h1>${content.title}</h1>
      <p>${content.intro}</p>
      <p class="legal-meta">${content.updated}</p>
      <p class="legal-alert">${content.alert}</p>
    `;
  }

  if (sideCard) {
    sideCard.innerHTML = `
      <h2>${content.sideTitle}</h2>
      <ul class="legal-sidecard-list">
        ${content.sideItems.map((item) => `<li><strong>${item.title}</strong>${item.text}</li>`).join("")}
      </ul>
    `;
  }

  if (summary) {
    summary.innerHTML = content.summaries
      .map((item) => `<article class="legal-summary-card"><h3>${item.title}</h3><p>${item.text}</p></article>`)
      .join("");
  }

  if (sections) {
    sections.innerHTML = content.sections
      .map((section) => {
        const paragraphs = (section.paragraphs || []).map((paragraph) => `<p>${paragraph}</p>`).join("");
        const list = Array.isArray(section.list) && section.list.length
          ? `<ul>${section.list.map((item) => `<li>${item}</li>`).join("")}</ul>`
          : "";
        const listGroups = Array.isArray(section.listGroups)
          ? section.listGroups.map((group) => `<h3>${group.title}</h3><ul>${group.items.map((item) => `<li>${item}</li>`).join("")}</ul>`).join("")
          : "";
        const extraParagraphs = (section.extraParagraphs || []).map((paragraph) => `<p>${paragraph}</p>`).join("");
        return `<article class="legal-section"><h2>${section.title}</h2>${paragraphs}${list}${listGroups}${extraParagraphs}</article>`;
      })
      .join("");
  }

  if (footerNote) {
    footerNote.textContent = content.footerNote;
  }
}

if (document.body?.dataset?.legalPage) {
  renderLegalPage();
  document.addEventListener("languageChanged", renderLegalPage);
}
